1	// claim-office.ts
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	
5	type QuoteStep = { op: string; items: Item[] };
6	
7	type Damage = { itemType: string; amount: number };
8	
9	type Incident = { cause: string; damages: Damage[] };
10	
11	type ClaimStep = { op: string; policy: number; incident: Incident };
12	
13	type Step = QuoteStep | ClaimStep;
14	
15	type Customer = { yearsWithMHPCO: number };
16	
17	type Scenario = {
18	  customer: Customer;
19	  steps: Step[];
20	};
21	
22	type QuoteResult = { premium: number };
23	
24	type ClaimResult = { payout: number; remainingCap: number };
25	
26	type StepResult = QuoteResult | ClaimResult;
27	
28	type ScenarioResult = {
29	  results: StepResult[];
30	};
31	
32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const PROCESSING_FEE = 5;
43	
44	const BLOCK_SIZE = 3;
45	const BLOCK_BASE_PREMIUM = 60;
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	
49	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
50	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
51	
52	const LOYALTY_DISCOUNT_RATE = 0.2;
53	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
54	
55	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
56	
57	const DEDUCTIBLE = 100;
58	const PAYOUT_CAP_MULTIPLIER = 2;
59	
60	const HIGH_ENCHANTMENT_THRESHOLD = 8;
61	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
62	const FULL_REIMBURSEMENT_RATE = 1;
63	
64	const INSURANCE_VALUES: Record<string, number> = {
65	  sword: 1000,
66	  amulet: 600,
67	  staff: 800,
68	  potion: 400,
69	  rune: 250,
70	  moonstone: 250,
71	};
72	
73	const countItemsByType = (items: Item[]): Map<string, number> => {
74	  const counts = new Map<string, number>();
75	  for (const item of items) {
76	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
77	  }
78	  return counts;
79	};
80	
81	const basePremiumForType = (type: string): number => {
82	  const basePremium = BASE_PREMIUMS[type];
83	  if (basePremium === undefined) {
84	    throw new Error(`Unknown item type: ${type}`);
85	  }
86	  return basePremium;
87	};
88	
89	const basePremiumForGroup = (type: string, count: number): number => {
90	  const basePremium = basePremiumForType(type);
91	  return count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * basePremium;
92	};
93	
94	const totalBasePremium = (items: Item[]): number =>
95	  [...countItemsByType(items)].reduce(
96	    (total, [type, count]) => total + basePremiumForGroup(type, count),
97	    0,
98	  );
99	
100	const curseSurchargeForItem = (item: Item): number =>
101	  item.cursed ? basePremiumForType(item.type) * CURSE_SURCHARGE_RATE : 0;
102	
103	const enchantmentSurchargeForItem = (item: Item): number =>
104	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
105	    ? basePremiumForType(item.type) * ENCHANTMENT_SURCHARGE_RATE
106	    : 0;
107	
108	const totalItemSurcharge = (items: Item[]): number =>
109	  items.reduce(
110	    (total, item) =>
111	      total + curseSurchargeForItem(item) + enchantmentSurchargeForItem(item),
112	    0,
113	  );
114	
115	const policyDiscountRate = (customer: Customer, stepIndex: number): number => {
116	  const loyaltyDiscountRate =
117	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
118	      ? LOYALTY_DISCOUNT_RATE
119	      : 0;
120	  const followUpDiscountRate = stepIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0;
121	  return loyaltyDiscountRate + followUpDiscountRate;
122	};
123	
124	const payoutCapForItems = (items: Item[]): number =>
125	  PAYOUT_CAP_MULTIPLIER *
126	  items.reduce((total, item) => total + INSURANCE_VALUES[item.type], 0);
127	
128	const reimbursementRateForItem = (item: Item): number =>
129	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
130	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
131	    : FULL_REIMBURSEMENT_RATE;
132	
133	const payoutForDamage = (damage: Damage, policyItems: Item[]): number => {
134	  if (damage.amount < 0) {
135	    throw new Error(`Negative damage amount: ${damage.amount}`);
136	  }
137	  const damagedItem = policyItems.find(
138	    (item) => item.type === damage.itemType,
139	  );
140	  if (damagedItem === undefined) {
141	    throw new Error(`Item type not covered by policy: ${damage.itemType}`);
142	  }
143	  return damage.amount * reimbursementRateForItem(damagedItem) - DEDUCTIBLE;
144	};
145	
146	const assertDamagesWithinCoverage = (
147	  damages: Damage[],
148	  policyItems: Item[],
149	): void => {
150	  const coveredCounts = countItemsByType(policyItems);
151	  const claimedCounts = countItemsByType(
152	    damages.map((damage) => ({ type: damage.itemType })),
153	  );
154	  for (const [type, claimed] of claimedCounts) {
155	    if (claimed > (coveredCounts.get(type) ?? 0)) {
156	      throw new Error(
157	        `More damage entries than covered items of type: ${type}`,
158	      );
159	    }
160	  }
161	};
162	
163	const incidentPayout = (incident: Incident, policyItems: Item[]): number => {
164	  assertDamagesWithinCoverage(incident.damages, policyItems);
165	  return Math.floor(
166	    incident.damages.reduce(
167	      (total, damage) => total + payoutForDamage(damage, policyItems),
168	      0,
169	    ),
170	  );
171	};
172	
173	const isClaimStep = (step: Step): step is ClaimStep => "incident" in step;
174	
175	const processClaimStep = (
176	  step: ClaimStep,
177	  steps: Step[],
178	  paidByPolicy: Map<number, number>,
179	): ClaimResult => {
180	  const policyItems = (steps[step.policy] as QuoteStep).items;
181	  const alreadyPaid = paidByPolicy.get(step.policy) ?? 0;
182	  const remainingCapBeforeClaim = payoutCapForItems(policyItems) - alreadyPaid;
183	  const payout = Math.min(
184	    incidentPayout(step.incident, policyItems),
185	    remainingCapBeforeClaim,
186	  );
187	  paidByPolicy.set(step.policy, alreadyPaid + payout);
188	  return {
189	    payout,
190	    remainingCap: remainingCapBeforeClaim - payout,
191	  };
192	};
193	
194	const processQuoteStep = (
195	  step: QuoteStep,
196	  customer: Customer,
197	  stepIndex: number,
198	): QuoteResult => {
199	  const basePremium = totalBasePremium(step.items);
200	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
201	  const itemSurcharge = totalItemSurcharge(step.items);
202	  const discount = basePremium * policyDiscountRate(customer, stepIndex);
203	  return {
204	    premium: Math.ceil(
205	      basePremium + firstInsuranceSurcharge + itemSurcharge - discount +
206	        PROCESSING_FEE,
207	    ),
208	  };
209	};
210	
211	export const processScenario = (scenario: Scenario): ScenarioResult => {
212	  const paidByPolicy = new Map<number, number>();
213	  return {
214	    results: scenario.steps.map((step, index) =>
215	      isClaimStep(step)
216	        ? processClaimStep(step, scenario.steps, paidByPolicy)
217	        : processQuoteStep(step, scenario.customer, index),
218	    ),
219	  };
220	};
